Here's the refactored code using async/await with proper error handling:

```js
async function run() {
  try {
    const user = await fetchUserAsync(id);
    return { user, orders: await enrichOrdersAsync(await fetchOrdersAsync(user.id)) };
  } catch (err) {
    const step = err.step || 'unknown';
    console.error(`Step failed: ${step}`);
    throw err;
  }
}

// Helper functions to promisify the callback-based functions
function fetchUserAsync(id) {
  return new Promise((resolve, reject) => {
    fetchUser(id, (err, user) => {
      if (err) {
        err.step = 'fetchUser';
        reject(err);
      } else {
        resolve(user);
      }
    });
  });
}

function fetchOrdersAsync(userId) {
  return new Promise((resolve, reject) => {
    fetchOrders(userId, (err, orders) => {
      if (err) {
        err.step = 'fetchOrders';
        reject(err);
      } else {
        resolve(orders);
      }
    });
  });
}

function enrichOrdersAsync(orders) {
  return new Promise((resolve, reject) => {
    enrichOrders(orders, (err, enriched) => {
      if (err) {
        err.step = 'enrichOrders';
        reject(err);
      } else {
        resolve(enriched);
      }
    });
  });
}
```

**Alternative approach** if you prefer to keep the logic more explicit:

```js
async function run() {
  let user, orders, enriched;

  try {
    user = await fetchUserAsync(id);
  } catch (err) {
    console.error('Step failed: fetchUser');
    throw err;
  }

  try {
    orders = await fetchOrdersAsync(user.id);
  } catch (err) {
    console.error('Step failed: fetchOrders');
    throw err;
  }

  try {
    enriched = await enrichOrdersAsync(orders);
  } catch (err) {
    console.error('Step failed: enrichOrders');
    throw err;
  }

  return { user, orders: enriched };
}
```

The first approach is more concise, while the second gives you more granular control over error handling for each step. Both preserve the original error handling behavior while eliminating callback hell.
